import React, { useState, useCallback, useEffect, useMemo } from 'react';
import {
  Button,
  Input,
  Select,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { ReceivablePayableDto } from '../../../services/kt/models';
import { reportPageLabels } from '../../../constants/reportPageLabels';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { selectPlaceholderClass } from '../../../utils/selectField';
import erp from '../../../styles/erpPage.module.css';

const CUSTOMER_TYPE_FILTER_OPTIONS = [
  { value: 'Customer', label: reportPageLabels.congNo.customerTypeCustomer },
  { value: 'Supplier', label: reportPageLabels.congNo.customerTypeSupplier },
  { value: 'Both', label: reportPageLabels.congNo.customerTypeBoth },
];

const labels = reportPageLabels.congNo;
const TEST_ID = 'erp-cong-no';
const PAGE_ID = 'kt-cong-no';

const CongNoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [asOfDate, setAsOfDate] = useState(new Date().toISOString().slice(0, 10));
  const [customerType, setCustomerType] = useState('');
  const [items, setItems] = useState<ReceivablePayableDto[]>([]);
  const [loading, setLoading] = useState(false);
  const { showTableLoading } = useCatalogTableBusy(loading);

  const handleLoad = useCallback(() => {
    setLoading(true);
    ktService.getReceivablePayable({ asOfDate, customerType: customerType || undefined })
      .then(setItems)
      .catch(err => dispatchAppToast(dispatch, { message: getApiErrorMessage(err, labels.loadError), type: 'error' }))
      .finally(() => setLoading(false));
  }, [asOfDate, customerType, dispatch]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) handleLoad(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [handleLoad]);

  const hasData = items.length > 0;

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-asOfDate`,
        content: (
          <Input type="date" value={asOfDate} onChange={e => setAsOfDate(e.target.value)} />
        ),
      },
      {
        testId: `${TEST_ID}-field-customerType`,
        content: (
          <Select
            value={customerType}
            onChange={e => setCustomerType(e.target.value)}
            options={CUSTOMER_TYPE_FILTER_OPTIONS}
            placeholder={labels.customerTypeAll}
            className={selectPlaceholderClass(customerType)}
          />
        ),
      },
      {
        testId: `${TEST_ID}-view-btn`,
        content: (
          <Button variant="primary" onClick={handleLoad} loading={loading} data-testid={`${TEST_ID}-view-btn`}>
            {labels.view}
          </Button>
        ),
      },
    ],
    [asOfDate, customerType, handleLoad, loading],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: handleLoad,
      canChart: false,
      canPrint: hasData,
      onPrint: () => window.print(),
    }),
    [handleLoad, hasData],
  );

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty}</div>
  ) : !showTableLoading ? (
    <div className={erp.tableWrapper}>
      <table className={erp.table}>
        <thead>
          <tr>
            <th>{labels.colCustomer}</th>
            <th>{labels.colType}</th>
            <th className={erp.colRight}>{labels.colTotalDebit}</th>
            <th className={erp.colRight}>{labels.colTotalCredit}</th>
            <th className={erp.colRight}>{labels.colBalance}</th>
          </tr>
        </thead>
        <tbody>
          {items.map(r => (
            <tr key={r.customerId}>
              <td>{r.customerName}</td>
              <td>{r.customerType}</td>
              <td className={erp.colRight}>{formatVnd(r.totalDebit)}</td>
              <td className={erp.colRight}>{formatVnd(r.totalCredit)}</td>
              <td className={erp.colRight}>{formatVnd(r.balance)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-users',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.title}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default CongNoPage;
